#nullable enable // autogenerated  

using System.Collections.Generic;
using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Callbacks;
using MVZ2.Vanilla.Properties;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Buffs
{
    [AutoBuffDefinition(VanillaBuffNames.Entity.RadiationProtection)]
    public class RadiationProtection : BuffDefinition
    {
        public RadiationProtection(string nsp, string name) : base(nsp, name)
        {
            // 注册回调：实体即将受到伤害前触发  
            AddTrigger(VanillaLevelCallbacks.PRE_ENTITY_TAKE_DAMAGE, PreEntityTakeDamageCallback, priority: -100);
        }

        private void PreEntityTakeDamageCallback(VanillaLevelCallbacks.PreTakeDamageParams param, CallbackResult result)
        {
            var damageInfo = param.input;
            var entity = damageInfo.Entity;
            if (entity == null)
                return;

            // 只减免带“辐射”效果的伤害  
            if (!damageInfo.Effects.HasEffect(VanillaDamageEffects.RADIATION))
                return;

            // 只取最高的辐射保护等级  
            float level = GetProtectionLevel(entity);
            if (level <= 0f)
                return;

            damageInfo.Multiply(1f - level); // 乘以 (1 - 最高保护等级)  
        }

        // 取实体身上所有 RadiationProtection buff 中最高的保护等级（0~1）。  
        // 供伤害减免与最大生命值减免逻辑共用。  
        public static float GetProtectionLevel(Entity entity)
        {
            if (entity == null)
                return 0f;

            buffBuffer.Clear();
            entity.GetBuffs<RadiationProtection>(buffBuffer);
            float max = 0f;
            foreach (var buff in buffBuffer)
            {
                float level = buff.GetProperty<float>(PROP_Protection_Level);
                if (level > max)
                    max = level;
            }
            buffBuffer.Clear();
            return max;
        }

        // 复用缓冲，避免每帧分配  
        private static readonly List<Buff> buffBuffer = new List<Buff>();

        // 定义一个 Buff 属性元数据，用于存储保护等级  
        public static readonly VanillaBuffPropertyMeta<float> PROP_Protection_Level =
            new VanillaBuffPropertyMeta<float>("Protection_Level");
    }
}
